CATALOGS: dict[str, list[Tool]] = {
    "scn-wannacry-w1": _W1,
    "scn-r5-phishing": _R5,
    "scn-c5-edr": _C5,
}


def catalog(scenario_id: str) -> list[Tool]:
    return CATALOGS.get(scenario_id, [])


def by_id(scenario_id: str) -> dict[str, Tool]:
    return {t.id: t for t in catalog(scenario_id)}
